/*
 * COMP 321 Project 4: Shell
 *
 * This program implements a tiny shell with job control.
 *
 * <Put your name(s) and NetID(s) here>
 */

#include <sys/types.h>
#include <sys/wait.h>

#include <assert.h>
#include <ctype.h>
#include <errno.h>
#include <signal.h>
#include <stdbool.h>
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>

// You may assume that these constants are large enough.
#define MAXLINE      1024   // max line size
#define MAXARGS       128   // max args on a command line
#define MAXJOBS        16   // max jobs at any point in time
#define MAXJID   (1 << 16)  // max job ID

// The job states are:
#define UNDEF 0 // undefined
#define FG 1    // running in foreground
#define BG 2    // running in background
#define ST 3    // stopped

/*
 * The job state transitions and enabling actions are:
 *     FG -> ST  : ctrl-z
 *     ST -> FG  : fg command
 *     ST -> BG  : bg command
 *     BG -> FG  : fg command
 * At most one job can be in the FG state.
 */

struct Job {
	pid_t pid;              // job PID
	int jid;                // job ID [1, 2, ...]
	int state;              // UNDEF, FG, BG, or ST
	char cmdline[MAXLINE];  // command line
};
typedef volatile struct Job *JobP;

/*
 * Define the jobs list using the "volatile" qualifier because it is accessed
 * by a signal handler (as well as the main program).
 */
static volatile struct Job jobs[MAXJOBS];
static int nextjid = 1;            // next job ID to allocate

extern char **environ;             // defined by libc

static char prompt[] = "tsh> ";    // command line prompt (DO NOT CHANGE)
static bool verbose = false;       // If true, print additional output.

// Search path variables.
static char *pathcopy = NULL;      // Saved copy of PATH string
static char **pathdirs = NULL;     // Array of directory strings
static int npathdirs = 0;          // Number of directories in path
static bool path_is_null = true;   // Whether PATH was NULL

/*
 * The following array can be used to map a signal number to its name.
 * This mapping is valid for x86(-64)/Linux systems, such as CLEAR.
 * The mapping for other versions of Unix, such as FreeBSD, Mac OS X, or
 * Solaris, differ!
 */
static const char *const signame[NSIG] = {
	"Signal 0",
	"HUP",				/* SIGHUP */
	"INT",				/* SIGINT */
	"QUIT",				/* SIGQUIT */
	"ILL",				/* SIGILL */
	"TRAP",				/* SIGTRAP */
	"ABRT",				/* SIGABRT */
	"BUS",				/* SIGBUS */
	"FPE",				/* SIGFPE */
	"KILL",				/* SIGKILL */
	"USR1",				/* SIGUSR1 */
	"SEGV",				/* SIGSEGV */
	"USR2",				/* SIGUSR2 */
	"PIPE",				/* SIGPIPE */
	"ALRM",				/* SIGALRM */
	"TERM",				/* SIGTERM */
	"STKFLT",			/* SIGSTKFLT */
	"CHLD",				/* SIGCHLD */
	"CONT",				/* SIGCONT */
	"STOP",				/* SIGSTOP */
	"TSTP",				/* SIGTSTP */
	"TTIN",				/* SIGTTIN */
	"TTOU",				/* SIGTTOU */
	"URG",				/* SIGURG */
	"XCPU",				/* SIGXCPU */
	"XFSZ",				/* SIGXFSZ */
	"VTALRM",			/* SIGVTALRM */
	"PROF",				/* SIGPROF */
	"WINCH",			/* SIGWINCH */
	"IO",				/* SIGIO */
	"PWR",				/* SIGPWR */
	"Signal 31"
};

// You must implement the following functions:

static bool	builtin_cmd(char **argv);
static void	do_bgfg(char **argv);
static void	eval(const char *cmdline);
static void	initpath(const char *pathstr);
static void	waitfg(pid_t pid);

static void	sigchld_handler(int signum);
static void	sigint_handler(int signum);
static void	sigtstp_handler(int signum);

// We are providing the following functions to you:

static bool	parseline(const char *cmdline, char **argv);

static void	sigquit_handler(int signum);

static bool	addjob(JobP jobs, pid_t pid, int state, const char *cmdline);
static void	clearjob(JobP job);
static bool	deletejob(JobP jobs, pid_t pid);
static pid_t	fgpid(JobP jobs);
static JobP	getjobjid(JobP jobs, int jid); 
static JobP	getjobpid(JobP jobs, pid_t pid);
static void	initjobs(JobP jobs);
static void	listjobs(JobP jobs);
static int	maxjid(JobP jobs); 
static int	pid2jid(pid_t pid); 

static void	app_error(const char *msg);
static void	unix_error(const char *msg);
static void	usage(void);

static void	Sio_error(const char s[]);
static ssize_t	Sio_putl(long v);
static ssize_t	Sio_puts(const char s[]);
static void	sio_error(const char s[]);
static void	sio_ltoa(long v, char s[], int b);
static ssize_t	sio_putl(long v);
static ssize_t	sio_puts(const char s[]);
static void	sio_reverse(char s[]);
static size_t	sio_strlen(const char s[]);

/*
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
int
main(int argc, char **argv) 
{
	struct sigaction action;
	int c;
	char cmdline[MAXLINE];
	char *path = NULL;
	bool emit_prompt = true;	// Emit a prompt by default.

	/*
	 * Redirect stderr to stdout (so that driver will get all output
	 * on the pipe connected to stdout).
	 */
	if (dup2(1, 2) < 0)
		unix_error("dup2 error");

	// Parse the command line.
	while ((c = getopt(argc, argv, "hvp")) != -1) {
		switch (c) {
		case 'h':             // Print a help message.
			usage();
			break;
		case 'v':             // Emit additional diagnostic info.
			verbose = true;
			break;
		case 'p':             // Don't print a prompt.
			// This is handy for automatic testing.
			emit_prompt = false;
			break;
		default:
			usage();
		}
	}

	/*
	 * Install sigint_handler() as the handler for SIGINT (ctrl-c).  SET
	 * action.sa_mask TO REFLECT THE SYNCHRONIZATION REQUIRED BY YOUR
	 * IMPLEMENTATION OF sigint_handler().
	 */
	action.sa_handler = sigint_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&action.sa_mask, SIGCHLD) < 0)
		unix_error("sigaddset error");
	if (sigaddset(&action.sa_mask, SIGTSTP) < 0)
		unix_error("sigaddset error");
	if (sigaction(SIGINT, &action, NULL) < 0)
		unix_error("sigaction error");

	/*
	 * Install sigtstp_handler() as the handler for SIGTSTP (ctrl-z).  SET
	 * action.sa_mask TO REFLECT THE SYNCHRONIZATION REQUIRED BY YOUR
	 * IMPLEMENTATION OF sigtstp_handler().
	 */
	action.sa_handler = sigtstp_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&action.sa_mask, SIGCHLD) < 0)
		unix_error("sigaddset error");
	if (sigaddset(&action.sa_mask, SIGINT) < 0)
		unix_error("sigaddset error");
	if (sigaction(SIGTSTP, &action, NULL) < 0)
		unix_error("sigaction error");

	/*
	 * Install sigchld_handler() as the handler for SIGCHLD (terminated or
	 * stopped child).  SET action.sa_mask TO REFLECT THE SYNCHRONIZATION
	 * REQUIRED BY YOUR IMPLEMENTATION OF sigchld_handler().
	 */
	action.sa_handler = sigchld_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&action.sa_mask, SIGINT) < 0)
		unix_error("sigaddset error");
	if (sigaddset(&action.sa_mask, SIGTSTP) < 0)
		unix_error("sigaddset error");
	if (sigaction(SIGCHLD, &action, NULL) < 0)
		unix_error("sigaction error");

	/*
	 * Install sigquit_handler() as the handler for SIGQUIT.  This handler
	 * provides a clean way for the test harness to terminate the shell.
	 * Preemption of the processor by the other signal handlers during
	 * sigquit_handler() does no harm, so action.sa_mask is set to empty.
	 */
	action.sa_handler = sigquit_handler;
	action.sa_flags = SA_RESTART;
	if (sigemptyset(&action.sa_mask) < 0)
		unix_error("sigemptyset error");
	if (sigaction(SIGQUIT, &action, NULL) < 0)
		unix_error("sigaction error");

	// Initialize the search path.
	path = getenv("PATH");
	initpath(path);

	// Initialize the jobs list.
	initjobs(jobs);

	// Execute the shell's read/eval loop.
	while (true) {

		// Read the command line.
		if (emit_prompt) {
			printf("%s", prompt);
			fflush(stdout);
		}
		if (fgets(cmdline, MAXLINE, stdin) == NULL && ferror(stdin))
			app_error("fgets error");
		if (feof(stdin)) // End of file (ctrl-d)
			exit(0);

		// Evaluate the command line.
		eval(cmdline);
		fflush(stdout);
	}

	// Control never reaches here.
	assert(false);
}

/* 
 * eval - Evaluate the command line that the user has just typed in.
 * 
 * If the user has requested a built-in command (quit, jobs, bg or fg)
 * then execute it immediately.  Otherwise, fork a child process and
 * run the job in the context of the child.  If the job is running in
 * the foreground, wait for it to terminate and then return.  Note:
 * each child process must have a unique process group ID so that our
 * background children don't receive SIGINT (SIGTSTP) from the kernel
 * when we type ctrl-c (ctrl-z) at the keyboard.  
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
eval(const char *cmdline)
{
	char *argv[MAXARGS];
	bool bg;
	pid_t pid;
	sigset_t mask, prev;
	char path[MAXLINE];
	int i;
	JobP job;

	// Parse the command line.
	bg = parseline(cmdline, argv);

	// Ignore empty lines.
	if (argv[0] == NULL)
		return;

	// Check for built-in commands.
	if (builtin_cmd(argv))
		return;

	// Block SIGCHLD before forking.
	if (sigemptyset(&mask) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&mask, SIGCHLD) < 0)
		unix_error("sigaddset error");
	if (sigprocmask(SIG_BLOCK, &mask, &prev) < 0)
		unix_error("sigprocmask error");

	// Fork a child process.
	if ((pid = fork()) < 0)
		unix_error("fork error");

	if (pid == 0) {
		// Child process.

		// Unblock SIGCHLD in the child.
		if (sigprocmask(SIG_SETMASK, &prev, NULL) < 0)
			unix_error("sigprocmask error");

		// Put child in a new process group.
		if (setpgid(0, 0) < 0)
			unix_error("setpgid error");

		// Resolve the executable path and exec.
		if (strchr(argv[0], '/') != NULL || path_is_null) {
			// Name contains '/' or PATH is NULL: use directly.
			execve(argv[0], argv, environ);
			printf("%s: Command not found\n", argv[0]);
			exit(0);
		}

		// Search the PATH directories.
		for (i = 0; i < npathdirs; i++) {
			if (pathdirs[i][0] == '\0') {
				// Empty entry means current directory.
				snprintf(path, MAXLINE, "%s", argv[0]);
			} else {
				snprintf(path, MAXLINE, "%s/%s",
				    pathdirs[i], argv[0]);
			}
			execve(path, argv, environ);
		}
		printf("%s: Command not found\n", argv[0]);
		exit(0);
	}

	// Parent process: add the child to the job list.
	addjob(jobs, pid, bg ? BG : FG, cmdline);

	if (bg) {
		// Unblock SIGCHLD.
		if (sigprocmask(SIG_SETMASK, &prev, NULL) < 0)
			unix_error("sigprocmask error");

		// Print background job info.
		job = getjobpid(jobs, pid);
		if (job != NULL)
			printf("[%d] (%d) %s", job->jid, (int)pid, cmdline);
	} else {
		// Wait for foreground job (SIGCHLD still blocked).
		waitfg(pid);

		// Unblock SIGCHLD.
		if (sigprocmask(SIG_SETMASK, &prev, NULL) < 0)
			unix_error("sigprocmask error");
	}
}

/* 
 * parseline - Parse the command line and build the argv array.
 *
 * Requires:
 *   "cmdline" is a NUL ('\0') terminated string with a trailing
 *   '\n' character.  "cmdline" must contain less than MAXARGS
 *   arguments.
 *
 * Effects:
 *   Builds "argv" array from space delimited arguments on the command line.
 *   The final element of "argv" is set to NULL.  Characters enclosed in
 *   single quotes are treated as a single argument.  Returns true if
 *   the user has requested a BG job and false if the user has requested
 *   a FG job.
 *
 * Note:
 *   In the textbook, this function has the return type "int", but "bool"
 *   is more appropriate.
 */
static bool
parseline(const char *cmdline, char **argv) 
{
	int argc;                   // number of args
	static char array[MAXLINE]; // local copy of command line
	char *buf = array;          // ptr that traverses command line
	char *delim;                // points to first space delimiter
	bool bg;                    // background job?

	strcpy(buf, cmdline);

	// Replace trailing '\n' with space.
	buf[strlen(buf) - 1] = ' ';

	// Ignore leading spaces.
	while (*buf != '\0' && *buf == ' ')
		buf++;

	// Build the argv list.
	argc = 0;
	if (*buf == '\'') {
		buf++;
		delim = strchr(buf, '\'');
	} else
		delim = strchr(buf, ' ');
	while (delim != NULL) {
		argv[argc++] = buf;
		*delim = '\0';
		buf = delim + 1;
		while (*buf != '\0' && *buf == ' ')	// Ignore spaces.
			buf++;
		if (*buf == '\'') {
			buf++;
			delim = strchr(buf, '\'');
		} else
			delim = strchr(buf, ' ');
	}
	argv[argc] = NULL;

	// Ignore blank line.
	if (argc == 0)
		return (true);

	// Should the job run in the background?
	if ((bg = (*argv[argc - 1] == '&')) != 0)
		argv[--argc] = NULL;

	return (bg);
}

/* 
 * builtin_cmd - If the user has typed a built-in command then execute
 *  it immediately.  
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 *
 * Note:
 *   In the textbook, this function has the return type "int", but "bool"
 *   is more appropriate.
 */
static bool
builtin_cmd(char **argv)
{

	// Handle the "quit" command.
	if (strcmp(argv[0], "quit") == 0)
		exit(0);

	// Handle the "jobs" command.
	if (strcmp(argv[0], "jobs") == 0) {
		listjobs(jobs);
		return (true);
	}

	// Handle the "bg" and "fg" commands.
	if (strcmp(argv[0], "bg") == 0 || strcmp(argv[0], "fg") == 0) {
		do_bgfg(argv);
		return (true);
	}

	return (false);     // This is not a built-in command.
}

/* 
 * do_bgfg - Execute the built-in bg and fg commands.
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
do_bgfg(char **argv)
{
	JobP job;
	char *id;
	pid_t pid;
	sigset_t mask_chld, prev_mask;

	// Check for the required argument.
	if (argv[1] == NULL) {
		printf("%s command requires PID or %%jobid argument\n",
		    argv[0]);
		return;
	}

	id = argv[1];

	if (id[0] == '%') {
		// JID argument.
		int jid = atoi(&id[1]);
		if (jid <= 0) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		job = getjobjid(jobs, jid);
		if (job == NULL) {
			printf("%s: No such job\n", id);
			return;
		}
	} else if (isdigit((unsigned char)id[0])) {
		// PID argument.
		pid_t lookup_pid = (pid_t)atoi(id);
		if (lookup_pid <= 0) {
			printf("%s: argument must be a PID or %%jobid\n",
			    argv[0]);
			return;
		}
		job = getjobpid(jobs, lookup_pid);
		if (job == NULL) {
			printf("(%d): No such process\n", (int)lookup_pid);
			return;
		}
	} else {
		printf("%s: argument must be a PID or %%jobid\n", argv[0]);
		return;
	}

	pid = job->pid;

	// Block SIGCHLD to avoid race conditions.
	if (sigemptyset(&mask_chld) < 0)
		unix_error("sigemptyset error");
	if (sigaddset(&mask_chld, SIGCHLD) < 0)
		unix_error("sigaddset error");
	if (sigprocmask(SIG_BLOCK, &mask_chld, &prev_mask) < 0)
		unix_error("sigprocmask error");

	// Send SIGCONT to restart the process group.
	if (kill(-pid, SIGCONT) < 0)
		unix_error("kill error");

	if (strcmp(argv[0], "fg") == 0) {
		// Run in the foreground.
		job->state = FG;
		waitfg(pid);
		if (sigprocmask(SIG_SETMASK, &prev_mask, NULL) < 0)
			unix_error("sigprocmask error");
	} else {
		// Run in the background.
		job->state = BG;
		if (sigprocmask(SIG_SETMASK, &prev_mask, NULL) < 0)
			unix_error("sigprocmask error");
		printf("[%d] (%d) %s", job->jid, (int)job->pid,
		    job->cmdline);
	}
}

/* 
 * waitfg - Block until process pid is no longer the foreground process.
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
waitfg(pid_t pid)
{
	sigset_t mask;

	if (sigemptyset(&mask) < 0)
		unix_error("sigemptyset error");

	// Wait until the process is no longer the foreground job.
	while (fgpid(jobs) == pid)
		sigsuspend(&mask);
}

/* 
 * initpath - Perform all necessary initialization of the search path,
 *  which may be simply saving the path.
 *
 * Requires:
 *   "pathstr" is a valid search path.
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
initpath(const char *pathstr)
{
	char *p;
	int count;

	if (pathstr == NULL) {
		path_is_null = true;
		return;
	}

	path_is_null = false;

	// Make a copy of the path string since we will modify it.
	pathcopy = strdup(pathstr);
	if (pathcopy == NULL)
		unix_error("strdup error");

	// Count the number of directories (number of ':' + 1).
	count = 1;
	for (p = pathcopy; *p != '\0'; p++) {
		if (*p == ':')
			count++;
	}

	// Allocate the directory array.
	pathdirs = malloc(count * sizeof(char *));
	if (pathdirs == NULL)
		unix_error("malloc error");

	// Split the path string by ':'.
	npathdirs = 0;
	pathdirs[npathdirs++] = pathcopy;
	for (p = pathcopy; *p != '\0'; p++) {
		if (*p == ':') {
			*p = '\0';
			pathdirs[npathdirs++] = p + 1;
		}
	}
}

/*
 * The signal handlers follow.
 */

/* 
 * sigchld_handler - The kernel sends a SIGCHLD to the shell whenever
 *  a child job terminates (becomes a zombie), or stops because it
 *  received a SIGSTOP or SIGTSTP signal.  The handler reaps all
 *  available zombie children, but doesn't wait for any other
 *  currently running children to terminate.  
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
sigchld_handler(int signum)
{
	int olderrno = errno;
	int status;
	pid_t pid;
	int jid;
	JobP job;

	// Prevent an "unused parameter" warning.
	(void)signum;

	// Reap all available zombie children.
	while ((pid = waitpid(-1, &status, WNOHANG | WUNTRACED)) > 0) {
		jid = pid2jid(pid);

		if (WIFEXITED(status)) {
			// Child exited normally.
			deletejob(jobs, pid);
		} else if (WIFSIGNALED(status)) {
			// Child terminated by a signal.
			Sio_puts("Job [");
			Sio_putl((long)jid);
			Sio_puts("] (");
			Sio_putl((long)pid);
			Sio_puts(") terminated by signal SIG");
			Sio_puts(signame[WTERMSIG(status)]);
			Sio_puts("\n");
			deletejob(jobs, pid);
		} else if (WIFSTOPPED(status)) {
			// Child stopped by a signal.
			job = getjobpid(jobs, pid);
			if (job != NULL)
				job->state = ST;
			Sio_puts("Job [");
			Sio_putl((long)jid);
			Sio_puts("] (");
			Sio_putl((long)pid);
			Sio_puts(") stopped by signal SIG");
			Sio_puts(signame[WSTOPSIG(status)]);
			Sio_puts("\n");
		}
	}

	errno = olderrno;
}

/* 
 * sigint_handler - The kernel sends a SIGINT to the shell whenever the
 *  user types ctrl-c at the keyboard.  Catch it and send it along
 *  to the foreground job.  
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
sigint_handler(int signum)
{
	int olderrno = errno;
	pid_t pid;

	// Prevent an "unused parameter" warning.
	(void)signum;

	// Forward SIGINT to the foreground job's process group.
	pid = fgpid(jobs);
	if (pid > 0) {
		if (kill(-pid, SIGINT) < 0)
			Sio_error("kill error\n");
	}

	errno = olderrno;
}

/*
 * sigtstp_handler - The kernel sends a SIGTSTP to the shell whenever
 *  the user types ctrl-z at the keyboard.  Catch it and suspend the
 *  foreground job by sending it a SIGTSTP.  
 *
 * Requires:
 *   <to be filled in by the student(s)>
 *
 * Effects:
 *   <to be filled in by the student(s)>
 */
static void
sigtstp_handler(int signum)
{
	int olderrno = errno;
	pid_t pid;

	// Prevent an "unused parameter" warning.
	(void)signum;

	// Forward SIGTSTP to the foreground job's process group.
	pid = fgpid(jobs);
	if (pid > 0) {
		if (kill(-pid, SIGTSTP) < 0)
			Sio_error("kill error\n");
	}

	errno = olderrno;
}

/*
 * sigquit_handler - The driver program can gracefully terminate the
 *  child shell by sending it a SIGQUIT signal.
 *
 * Requires:
 *   "signum" is SIGQUIT.
 *
 * Effects:
 *   Terminates the program.
 */
static void
sigquit_handler(int signum)
{

	// Prevent an "unused parameter" warning.
	(void)signum;
	Sio_puts("Terminating after receipt of SIGQUIT signal\n");
	_exit(1);
}

/*
 * This comment marks the end of the signal handlers.
 */

/*
 * The following helper routines manipulate the jobs list.
 */

/*
 * Requires:
 *   "job" points to a job structure.
 *
 * Effects:
 *   Clears the fields in the referenced job structure.
 */
static void
clearjob(JobP job)
{

	job->pid = 0;
